    #[test]
    fn legacy_memory_embedding_fields_warn_but_do_not_error() {
        let toml = r#"
[memory]
embedding_provider = "custom"
embedding_model = "intfloat/multilingual-e5-small"
embedding_base_url = "http://moltis-embeddings:7997/v1"
